    d2h_time = 0.0;
#endif

	// Copy result back
	for (int i = 0; i < cols; i++) {
		result[i] = (final_ret == 0) ? d_gpuResult0[i] : d_gpuResult1[i];
	}

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
